<template>
  <div class="more-service">
    <div v-for="item in moreServiceList" :key="item.categoryName">
      <div class="category-title">{{ item.categoryName }}</div>
      <div class="psd-item" v-for="(data, index) in item.productList" :key="index" @click="handleMoreService(data)">
        <el-image :src="data.thumbnail" class="psd-image" fit="fill"> </el-image>
        <div class="psd-tag psd-left-top">点击获取</div>
        <div class="psd-tag psd-right-bottom">
          <span
            ><p>{{ data.usersNum }}</p>
            人已经参加</span
          >
        </div>
      </div>
    </div>

    <Poster ref="posterRef" :posterStatus="posterStatus" :posterUrl="posterUrl" />
  </div>
</template>

<script>
import { getMoreServiceList } from '@/api/moreService';
import Poster from '@/components/Poster.vue';

export default {
  name: 'MoreService',
  props: {
    categoryParentId: {
      type: String,
      default: '9'
    }
  },
  components: {
    Poster
  },
  data() {
    return {
      moreServiceList: [],
      posterStatus: false,
      posterUrl: null
    };
  },
  created() {
    this.getMoreServices();
  },
  methods: {
    async getMoreServices() {
      let response = await getMoreServiceList({ firstCategoryId: this.categoryParentId });
      this.moreServiceList = response.data;
    },
    handleMoreService(item) {
      this.posterStatus = true;
      this.posterUrl = item.highDefinition;
    }
  }
};
</script>

